async (params, browser) => {
  // Open Top 250 page
  await browser.open('https://www.imdb.com/chart/top/')

  // Wait for list to load
  await browser.waitForSelector('.ipc-metadata-list-summary-item, [class*=\'ipc-metadata-list\'], [class*=\'chart\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll through list
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract Top 250 list
  const top250_data = await browser.evaluate(`const movies = []; const items = document.querySelectorAll('.ipc-metadata-list-summary-item, li[class*="ipc-metadata-list-summary-item"]'); for (let i = 0; i < Math.min(items.length, 50); i++) { const el = items[i]; const titleEl = el.querySelector('h3.ipc-title__text, .ipc-title__text, h3'); const metaItems = el.querySelectorAll('.cli-title-metadata-item, [class*="cli-title-metadata-item"]'); let year = ''; let runtime = ''; for (const m of metaItems) { const t = m.textContent.trim(); if (/^\d{4}$/.test(t)) { year = t; } else if (!runtime) { runtime = t; } } const ratingEl = el.querySelector('.ipc-rating-star--rating, [class*="ipc-rating-star--rating"]'); const linkEl = el.querySelector('a[href*="/title/"]'); const imgEl = el.querySelector('img'); let title = titleEl ? titleEl.textContent.trim() : ''; const rankMatch = title.match(/^(\d+)\.\s*(.*)/); const rank = rankMatch ? parseInt(rankMatch[1]) : i + 1; if (rankMatch) title = rankMatch[2]; movies.push({ rank: rank, title: title, year: year, rating: ratingEl ? ratingEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { list: 'IMDb Top 250', movie_count: movies.length, movies: movies, url: window.location.href }`)

  return top250_data
}
